Create deployment/skypilot/train_cloud_all.yaml:
  name: mnvss-train-cloud

  resources:
    disk_size: 150
    disk_tier: best
    use_spot: true
    any_of:
      - cloud: runpod
        accelerators: {A100:1}     # cheapest, spot only
      - cloud: lambda
        accelerators: {A100:1}     # reliable, no spot
      - cloud: aws
        accelerators: {A100:1}
      - cloud: gcp
        accelerators: {A100:1}

  file_mounts:
    /data:
      source: s3://minivess-data/raw
      mode: COPY
    /checkpoints:
      name: minivess-checkpoints
      store: s3
      mode: MOUNT_CACHED

  envs:
    MLFLOW_TRACKING_URI: ${MLFLOW_TRACKING_URI:-http://mlflow:5000}
    MODEL_FAMILY: ${MODEL_FAMILY:-dynunet}
    LOSS_NAME: ${LOSS_NAME:-cbdice_cldice}
    COMPUTE: ${COMPUTE:-gpu_low}
    NUM_FOLDS: ${NUM_FOLDS:-3}
    MAX_EPOCHS: ${MAX_EPOCHS:-100}
    CHECKPOINT_INTERVAL_EPOCHS: ${CHECKPOINT_INTERVAL_EPOCHS:-5}
    PREFECT_API_URL: ${PREFECT_API_URL:-}
    HF_TOKEN: ${HF_TOKEN:-}

  [same setup/run as train_generic.yaml, but using ${MODEL_FAMILY}]
